#!/usr/bin/env python3
"""Generate deterministic fake error-diagnostics test cases for Zig stdlib error diagnostics lab."""
import json, random

random.seed(42)

cases = []

def add(case_id, category, **kw):
    c = {
        "case_id": case_id,
        "category": category,
        "fake_record_name": kw.get("fake_record_name", f"fake_{case_id}"),
        "synthetic_input": kw.get("synthetic_input", f"fake_input_{case_id}"),
        "synthetic_token_label": kw.get("synthetic_token_label", "demo_token"),
        "expected_error_label": kw.get("expected_error_label", "None"),
        "expected_success": kw.get("expected_success", True),
        "expected_diagnostic_present": kw.get("expected_diagnostic_present", False),
        "expected_line": kw.get("expected_line", 0),
        "expected_column": kw.get("expected_column", 0),
        "expected_diagnostic_msg_preview": kw.get("expected_diagnostic_msg_preview", ""),
        "expected_cleanup_runs": kw.get("expected_cleanup_runs", False),
        "expected_errdefer_runs": kw.get("expected_errdefer_runs", False),
        "expected_defer_runs": kw.get("expected_defer_runs", True),
        "expected_catch_runs": kw.get("expected_catch_runs", False),
        "expected_optional_diagnostic": kw.get("expected_optional_diagnostic", False),
        "expected_json_context": kw.get("expected_json_context", False),
        "expected_zon_context": kw.get("expected_zon_context", False),
        "expected_compile_flag_context": kw.get("expected_compile_flag_context", False),
        "operation_label": kw.get("operation_label", "synthetic_parse_case"),
        "zig_feature": kw.get("zig_feature", "error_union"),
        "context_label": kw.get("context_label", "error_union_policy"),
        "expected_zig_status": kw.get("expected_zig_status", "success"),
        "expected_error_union_observation": kw.get("expected_error_union_observation", "success"),
        "expected_diagnostic_observation": kw.get("expected_diagnostic_observation", "none"),
        "expected_errdefer_observation": kw.get("expected_errdefer_observation", "not_run"),
        "expected_testing_observation": kw.get("expected_testing_observation", "pass"),
        "expected_json_zon_observation": kw.get("expected_json_zon_observation", "not_tested"),
        "expected_version_truth": kw.get("expected_version_truth", "local_only"),
        "expected_production_truth": kw.get("expected_production_truth", "not_tested"),
        "fail_reason": kw.get("fail_reason", ""),
        "naive_should_fail": kw.get("naive_should_fail", False),
    }
    cases.append(c)

