add("c01_error_union_success", "error_union_success_marker", fake_record_name="fake_success_case", synthetic_input="synthetic_parse_case_ok", expected_error_label="None", expected_success=True, zig_feature="error_union", context_label="error_union_policy")
add("c02_error_union_failure", "error_union_failure_marker", fake_record_name="fake_failure_case", synthetic_input="synthetic_parse_case_err", expected_error_label="ToyError", expected_success=False, expected_catch_runs=True, zig_feature="error_union", context_label="error_union_policy", expected_zig_status="error", expected_error_union_observation="error")
